BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?child ?childName ?childType WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name "TMT-APS-SE" .

  ?pkg vocab:Package_packagedElement ?child .
  OPTIONAL { ?child vocab:NamedElement_name ?childName . }
  ?child rdf:type ?childType .
}
ORDER BY LCASE(STR(?childType))
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?diagram ?diagramName WHERE {
  ?pkg rdf:type vocab:package ;
       vocab:NamedElement_name "TMT-APS-SE" .

  { 
    ?pkg vocab:ownedDiagram+ ?diagram .
  }
  UNION
  {
    ?diagram rdf:type vocab:Diagram ;
             vocab:ownerOfDiagram ?pkg .
  }
  OPTIONAL { ?diagram vocab:NamedElement_name ?diagramName . }

}
ORDER BY LCASE(STR(?diagramName))
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?diagram ?diagramName WHERE {
  ?rootPkg rdf:type vocab:package ;
            vocab:NamedElement_name "TMT-APS-SE" .

  ?rootPkg (vocab:Element_ownedElement+|^vocab:Element_owner+|vocab:Package_packagedElement+)
           ?diagram .
  ?diagram rdf:type vocab:Diagram .
  OPTIONAL { ?diagram vocab:NamedElement_name ?diagramName . }
}
ORDER BY LCASE(STR(?diagramName))
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?subPkg ?subName WHERE {
  ?rootPkg rdf:type vocab:package ;
            vocab:NamedElement_name "TMT-APS-SE" .

  {
    ?rootPkg vocab:nestedPackage+ ?subPkg .
  }
  UNION
  {
    ?rootPkg vocab:Package_packagedElement+ ?subPkg .
    ?subPkg rdf:type vocab:package .
  }
  OPTIONAL { ?subPkg vocab:NamedElement_name ?subName . }
}
ORDER BY LCASE(STR(?subName))
LIMIT 25
